        public MYOutline(Texture texture, int color)
        {
            texture__ = texture;

            const int DefaultColor = unchecked((int)0xFF000000);
            int packedColor = color;

            if (packedColor == 0 && color == 0)
            {
                packedColor = DefaultColor;
            }

            const float Inv255 = 1f / 255f;
            float a = ((uint)packedColor >> 24) * Inv255;
            float r = ((packedColor >> 16) & 0xFF) * Inv255;
            float g = ((packedColor >> 8) & 0xFF) * Inv255;
            float b = (packedColor & 0xFF) * Inv255;


            texture__ = texture;
            color__ = new Vector(Ref<double>.In(r), Ref<double>.In(g), Ref<double>.In(b), Ref<double>.In(a));          // 假设 Vector(double,double,double,double) 或 (float,float,float,float)
            threshold__ = 0.05;
            sprScaleX__ = 1;
            sprScaleY__ = 1;
            priority = -1;

            double texWidthInv = 1 / texture.width;
            double texHeightInv = 1 / texture.height;
            uvScale__ = new Vector(Ref<double>.In(texWidthInv), Ref<double>.In(texHeightInv), Ref<double>.In(0), Ref<double>.In(1f));
        }

        public override dynamic getParamValue(int index)
        {
            switch (index)
            {
                case 0: return this.texture__;
                case 1: return this.color__;
                case 2: return this.threshold__;
                case 3: return this.uvScale__;
                case 4: return this.sprScaleX__;
                case 5: return this.sprScaleY__;
                default: return null!;
            }
        }


        public override double getParamFloatValue(int index)
        {
            switch (index)
            {
                case 2: return this.threshold__;
                case 4: return this.sprScaleX__;
                case 5: return this.sprScaleY__;
                default: return 0;
            }
            ;
        }

